# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    
    # Check if the X-Enrich-URL header is present
    enrich_url_header = request['headers'].get('x-enrich-url', [{}])[0].get('value')
    
    if enrich_url_header:
        try:
            # Fetch additional data from the URL specified in the header
            response = requests.get(enrich_url_header, timeout=2)
            response.raise_for_status()
            
            # Parse the response as JSON
            context_data = response.json()
            
            # Append the context data to the request headers (e.g., for logging or processing later)
            if 'context-data' not in [header['key'].lower() for header in request['headers']]:
                request['headers'].append({
                    'key': 'Context-Data',
                    'value': json.dumps(context_data)
                })
        
        except requests.exceptions.RequestException as e:
            # Handle any exceptions that occur during the HTTP request
            print(f"Error fetching enrichment data: {str(e)}")
    
    # Forward the modified request to the origin server
    return request